```
#ifdef OPENTHREAD_CONFIG_FILE
#include OPENTHREAD_CONFIG_FILE
#else
#include <openthread-config.h>
#endif

//...

#if OPENTHREAD_ENABLE_DHCP6_CLIENT
//...
#endif
```

